section.code:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://faion.net/schemas/integration-testing",
  "type": "object",
  "required": ["dirs", "conftest", "ciSuiteTimeBudget"],
  "properties": {
    "dirs": {
      "type": "object",
      "required": ["unit", "integration"],
      "properties": {
        "unit": {"const": "tests/unit"},
        "integration": {"const": "tests/integration"}
      }
    },
    "conftest": {
      "type": "object",
      "required": ["containerScope", "sessionScope", "imageTag"],
      "properties": {
        "containerScope": {"const": "session"},
        "sessionScope":   {"const": "function"},
        "imageTag":       {"type": "string", "pattern": "^[a-z0-9-]+:[0-9.]+$"}
      }
    },
    "ciSuiteTimeBudget": {"type": "integer", "minimum": 1, "maximum": 300},
    "assertions": {
      "type": "array",
      "description": "Each test must assert both status and body.",
      "items": {"enum": ["status", "body"]}
    }
  }
}

example.code:
# tests/integration/conftest.py from testcontainers.postgres import PostgresContainer
@pytest.fixture(scope="session") def pg_url(): with PostgresContainer("postgres:16.2") as c: # r3: pinned yield c.get_connection_url()
@pytest.fixture(scope="session") def engine(pg_url): eng = create_engine(pg_url) Base.metadata.create_all(eng) yield eng
@pytest.fixture def db_session(engine): conn = engine.connect() tx = conn.begin() # r2: transaction SessionLocal = sessionmaker(bind=conn) session = SessionLocal() yield session session.close() tx.rollback() # rollback even on test fail conn.close()
@pytest.fixture def client(db_session): def _get_db(): yield db_session app.dependency_overrides[get_db] = _get_db # r8: DI override yield TestClient(app) app.dependency_overrides.clear() # r8: cleanup
# tests/integration/test_users.py def test_create_user(client): r = client.post("/users", json={"email": "a@b.com"}) assert r.status_code == 201 # r9: status body = r.json() assert body["email"] == "a@b.com" and body["id"] # r9: body shape

# REJECTED
@pytest.fixture
def db_session():
    with PostgresContainer("postgres:latest") as c:    # r3 violated: unpinned + per-test container
        eng = create_engine(c.get_connection_url())
        yield Session(eng)
        eng.execute("TRUNCATE TABLE users")             # r2 violated: teardown delete

def test_login(client):
    r = client.post("/login", json={...})
    assert r.status_code == 200                         # r9 violated: status-only assert
